const insert = db.prepare(`
  INSERT INTO parts (category,brand,name,price_usd,rating,tier,watt,stock,img,specs,
    perf_gaming,perf_workstation,perf_streaming,retailer_amazon,retailer_newegg,retailer_bhphoto,
    created_at,updated_at)
  VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,datetime('now'),datetime('now'))
`);

const insertAll = db.transaction(items => {
  for (const p of items) {
    insert.run(
      p.category, p.brand, p.name, p.price_usd,
      p.rating, p.tier, p.watt||0, p.stock,
      p.img||'', JSON.stringify(p.specs||{}),
      p.perf_gaming||0, p.perf_workstation||0, p.perf_streaming||0,
      p.retailer_amazon||'', p.retailer_newegg||'', p.retailer_bhphoto||''
    );
  }
});

